llmStructuredOutput.jsonSchema:
{
    "videoType": {
        "type": "string",
        "description": "Video type such as science explainer or campaign video"
    },
    "coreGoal": {
        "type": "string",
        "description": "Core production goal"
    },
    "desiredEffect": {
        "type": "string",
        "description": "Expected audience impact or effect"
    },
    "targetAudience": {
        "type": "string",
        "description": "Primary audience"
    },
    "deliveryChannel": {
        "type": "string",
        "description": "Delivery channel or publishing scene"
    },
    "language": {
        "type": "string",
        "description": "Voiceover or subtitle language"
    },
    "ratio": {
        "type": "string",
        "description": "Aspect ratio such as 16:9 or 9:16"
    },
    "duration": {
        "type": "string",
        "description": "Desired duration text"
    },
    "toneStyle": {
        "type": "string",
        "description": "Tone and visual style"
    },
    "mustIncludeFacts": {
        "type": "array",
        "items": {
            "type": "string"
        },
        "description": "Facts or points that must appear"
    },
    "callToAction": {
        "type": "string",
        "description": "Call to action or ending guidance"
    },
    "frameReferenceMode": {
        "type": "string",
        "description": "Frame reference mode"
    },
    "missingInputs": {
        "type": "array",
        "items": {
            "type": "string"
        },
        "description": "Still missing inputs after confirmation"
    }
}

